solution_code:
#include <stdio.h>

void swap_int(int *a, int *b) {
    int tmp = *a;
    *a = *b;
    *b = tmp;
}

void set_via_ptr(int **pp, int val) {
    **pp = val;
}

int main(void) {
    {
        int x = 3, y = 7;
        swap_int(&x, &y);
        printf("%d\n", (int)(x));
        printf("%d\n", (int)(y));
    }
    {
        int x = 5, y = 5;
        swap_int(&x, &y);
        printf("%d\n", (int)(x));
        printf("%d\n", (int)(y));
    }
    {
        int x = -10, y = 42;
        swap_int(&x, &y);
        printf("%d\n", (int)(x));
        printf("%d\n", (int)(y));
    }
    {
        int target = 0;
        int *p = &target;
        set_via_ptr(&p, 99);
        printf("%d\n", (int)(target));
    }
    {
        int val = 1000;
        int *p = &val;
        set_via_ptr(&p, -1);
        printf("%d\n", (int)(val));
    }
    return 0;
}
